import React, { useEffect } from 'react';
import { Linking, Alert, Text, View, StyleSheet } from 'react-native';
import { NavigationContainer, useNavigationContainerRef } from '@react-navigation/native';
import { createNativeStackNavigator } from '@react-navigation/native-stack';

// Placeholder Screens
const HomeScreen = () => (
  <View style={styles.screen}>
    <Text style={styles.text}>Welcome Home!</Text>
    <Text style={styles.subText}>Try opening deep links:</Text>
    <Text style={styles.linkText}>myapp://profile/123</Text>
    <Text style={styles.linkText}>myapp://payment/confirm</Text>
  </View>
);

const ProfileScreen = ({ route }) => (
  <View style={styles.screen}>
    <Text style={styles.text}>Profile Screen</Text>
    <Text style={styles.subText}>Profile ID: {route.params?.id || 'N/A'}</Text>
  </View>
);

const PaymentConfirmScreen = () => (
  <View style={styles.screen}>
    <Text style={styles.text}>Payment Confirmation</Text>
    <Text style={styles.subText}>Your payment is being processed.</Text>
  </View>
);

const Stack = createNativeStackNavigator();

const App = () => {
  const navigationRef = useNavigationContainerRef();

  const handleDeepLink = (eventOrUrl) => {
    const url = typeof eventOrUrl === 'string' ? eventOrUrl : eventOrUrl.url;
    
    // Ensure navigation container is ready before attempting to navigate
    if (!url || !navigationRef.isReady()) {
      return;
    }

    // Example URLs: myapp://profile/123, myapp://payment/confirm
    // Remove the scheme part to get the path: "profile/123" or "payment/confirm"
    const path = url.replace(/.*?:\/\//g, '');
    
    // Split the path into host (first segment) and remaining parameters
    const [host, ...params] = path.split('/');

    if (host === 'profile' && params.length > 0) {
      const profileId = params[0];
      navigationRef.navigate('Profile', { id: profileId });
    } else if (host === 'payment' && params[0] === 'confirm') {
      navigationRef.navigate('PaymentConfirm');
    } else {
      Alert.alert('Unknown Deep Link', `Could not handle: ${url}`);
      // Optionally navigate to a default screen if the deep link is not recognized
      // navigationRef.navigate('Home');
    }
  };

  useEffect(() => {
    // 1. Handle initial deep link when the app is launched from a URL
    Linking.getInitialURL().then((url) => {
      if (url) {
        handleDeepLink(url);
      }
    });

    // 2. Handle incoming deep links when the app is already running
    const subscription = Linking.addEventListener('url', handleDeepLink);

    return () => {
      // Clean up the event listener when the component unmounts
      subscription.remove();
    };
  }, []); // The empty dependency array ensures this effect runs only once on mount

  return (
    <NavigationContainer ref={navigationRef}>
      <Stack.Navigator initialRouteName="Home">
        <Stack.Screen name="Home" component={HomeScreen} options={{ title: 'Deep Link Demo' }} />
        <Stack.Screen name="Profile" component={ProfileScreen} options={{ title: 'User Profile' }} />
        <Stack.Screen name="PaymentConfirm" component={PaymentConfirmScreen} options={{ title: 'Confirm Payment' }} />
      </Stack.Navigator>
    </NavigationContainer>
  );
};

